input:
foreach my $item (@list) {
    next if skip_condition($item);
    process($item);
}

foreach my $item (@list) {
    process($item);
    last if stop_condition($item);
}

while ($condition) {
    my $input = get_input();
    redo if invalid($input);
    process($input);
}

OUTER: for my $i (1..10) {
    for my $j (1..10) {
        next OUTER if ($i * $j > 50);
        print "$i x $j = ", $i * $j, "\n";
    }
}

SEARCH: foreach my $item (@items) {
    foreach my $prop (@properties) {
        if ($item->{$prop} eq $target) {
            $found = $item;
            last SEARCH;
        }
    }
}

RETRY: while ($attempts < $max_attempts) {
    my $result = try_operation();
    if ($result eq 'retry') {
        $attempts++;
        redo RETRY;
    }
    return $result;
}

foreach my $batch (@batches) {
    foreach my $item (@{$batch}) {
        next if $item->{skip};
        my $result = process($item);
        if ($result->{error}) {
            log_error($result->{error});
            next;
        }
        last if $result->{complete};
    }
}

my $result = do {
    for my $item (@items) {
        if ($item->{target}) {
            last $item->{value};
        }
    }
    'default';
};
